#include <bits/stdc++.h>
using namespace std;
int main(){
    int t;long long n;
    cin>>t;
    for(int i=1;i<=t;i++){
        cin>>n;
        for(long long j=2;j*j<=n;j++){
            while(n%j==0){
                n/=j;
                cout<<j<<' ';
            }
        }
        if(n>1){
            cout<<n;
        }
        cout<<endl;
    }
}
